mapper.select:
select a.id,a.code,b.parent_code,a.value,b.is_plus,b.is_tax,b.name,b.is_fixed,b.is_compute from hrm_salary_month_option_value a inner join hrm_salary_option b on a.code = b.code inner join hrm_salary_month_emp_record c on c.s_emp_record_id = a.s_emp_record_id where c.employee_id = #{employeeId} and c.year=#{year} and c.month = #{month}
and b.parent_code in
#{code}
